import 'package:injectable/injectable.dart'; import 'package:url_launcher/url_launcher.dart'; import '../utils/app_logger.dart'; @singleton class UrlLauncherService { Future<bool> launch(String url) async { final uri = Uri.parse(url); if (await canLaunchUrl(uri)) { await launchUrl(uri, mode: LaunchMode.externalApplication); return true; } AppLogger.warning('Cannot launch: $url'); return false; } Future<void> openEmail(String email, {String? subject}) => launch('mailto:$email${subject != null ? "?subject=${Uri.encodeComponent(subject)}" : ""}'); Future<void> openPhone(String phone) => launch('tel:$phone'); }